import React from "react";
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend } from "recharts";

function BusCharts({ buses }) {
  // Aggregate buses for chart
  const chartData = buses.reduce((acc, bus) => {
    const time = new Date().toLocaleTimeString();
    let record = acc.find((r) => r.time === time);
    if (!record) {
      record = { time, Normal: 0, Ghost: 0 };
      acc.push(record);
    }
    if (bus.status === "ghost") record.Ghost += 1;
    else record.Normal += 1;
    return acc;
  }, []);

  return (
    <LineChart width={800} height={300} data={chartData} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
      <CartesianGrid strokeDasharray="3 3" />
      <XAxis dataKey="time" />
      <YAxis />
      <Tooltip />
      <Legend />
      <Line type="monotone" dataKey="Normal" stroke="green" />
      <Line type="monotone" dataKey="Ghost" stroke="red" />
    </LineChart>
  );
}

export default BusCharts;
